import jwt
import json
import base64
import time
from typing import Any


def decode_jwt_payload_without_verification(token: str) -> dict[str, Any]:
    """
    Decode a JWT token's payload WITHOUT verification.
    This is ONLY for inspecting token structure during debugging.
    NEVER use this for authentication or authorization decisions.
    """
    parts = token.split(".")
    if len(parts) != 3:
        raise ValueError("Invalid JWT token format: expected 3 parts separated by '.'")

    # Decode header
    header_padded = parts[0] + "=" * (4 - len(parts[0]) % 4)
    header = json.loads(base64.urlsafe_b64decode(header_padded))

    # Decode payload
    payload_padded = parts[1] + "=" * (4 - len(parts[1]) % 4)
    payload = json.loads(base64.urlsafe_b64decode(payload_padded))

    return {
        "header": header,
        "payload": payload,
        "signature_present": bool(parts[2]),
        "WARNING": "This payload is NOT verified. Do not trust these claims for auth decisions.",
    }


def verify_and_decode_jwt(
    token: str,
    secret_or_public_key: str,
    algorithms: list[str] | None = None,
    audience: str | None = None,
    issuer: str | None = None,
    require_exp: bool = True,
) -> dict[str, Any]:
    """
    Decode and VERIFY a JWT token securely.
    This should be used when you need to validate token authenticity.

    Args:
        token: The JWT token string.
        secret_or_public_key: The secret key (HMAC) or public key (RSA/EC) for verification.
        algorithms: Explicit list of allowed algorithms. MUST be specified to prevent
                    algorithm confusion attacks. Defaults to ["HS256"] if not provided.
        audience: Expected audience claim (aud). Validated if provided.
        issuer: Expected issuer claim (iss). Validated if provided.
        require_exp: Whether to require and validate the expiration claim.

    Returns:
        Dictionary with decoded and verified token information.

    Raises:
        ValueError: If parameters are insecure.
        jwt.InvalidTokenError: If token verification fails.
    """
    # SECURITY: Never allow "none" algorithm - prevents algorithm stripping attacks
    if algorithms is None:
        algorithms = ["HS256"]

    # SECURITY: Explicitly reject the "none" algorithm to prevent bypass attacks
    sanitized_algorithms = []
    for alg in algorithms:
        if alg.lower() == "none":
            raise ValueError(
                "The 'none' algorithm is not allowed. "
                "This would disable signature verification entirely."
            )
        sanitized_algorithms.append(alg)

    if not sanitized_algorithms:
        raise ValueError("At least one algorithm must be specified.")

    # SECURITY: Require a non-empty secret/key
    if not secret_or_public_key or not secret_or_public_key.strip():
        raise ValueError(
            "A non-empty secret or public key must be provided for verification."
        )

    # Build decode options
    options = {}
    required_claims = []

    if require_exp:
        required_claims.append("exp")

    if required_claims:
        options["require"] = required_claims

    # Decode with full verification
    decoded_payload = jwt.decode(
        token,
        secret_or_public_key,
        algorithms=sanitized_algorithms,
        audience=audience,
        issuer=issuer,
        options=options,
    )

    # Build result with helpful debug info
    result = {
        "verified": True,
        "payload": decoded_payload,
    }

    # Add human-readable timestamps for debugging
    if "exp" in decoded_payload:
        exp_time = decoded_payload["exp"]
        result["exp_human"] = time.strftime(
            "%Y-%m-%d %H:%M:%S UTC", time.gmtime(exp_time)
        )
        result["exp_remaining_seconds"] = exp_time - int(time.time())

    if "iat" in decoded_payload:
        iat_time = decoded_payload["iat"]
        result["iat_human"] = time.strftime(
            "%Y-%m-%d %H:%M:%S UTC", time.gmtime(iat_time)
        )

    if "nbf" in decoded_payload:
        nbf_time = decoded_payload["nbf"]
        result["nbf_human"] = time.strftime(
            "%Y-%m-%d %H:%M:%S UTC", time.gmtime(nbf_time)
        )

    return result


def debug_inspect_jwt(token: str, secret_or_public_key: str | None = None,
                      algorithms: list[str] | None = None,
                      audience: str | None = None,
                      issuer: str | None = None) -> dict[str, Any]:
    """
    Comprehensive JWT inspection for debugging. Attempts verification if a key is provided,
    and always includes the unverified payload for comparison.

    Args:
        token: The JWT token string.
        secret_or_public_key: Optional key for verification. If not provided,
                              only unverified inspection is performed.
        algorithms: Allowed algorithms for verification.
        audience: Expected audience for verification.
        issuer: Expected issuer for verification.

    Returns:
        Dictionary with inspection results.
    """
    result = {}

    # Always include unverified inspection for debugging structure
    try:
        result["unverified_inspection"] = decode_jwt_payload_without_verification(token)
    except Exception as e:
        result["unverified_inspection_error"] = str(e)

    # Attempt verification if key is provided
    if secret_or_public_key:
        try:
            verified = verify_and_decode_jwt(
                token=token,
                secret_or_public_key=secret_or_public_key,
                algorithms=algorithms,
                audience=audience,
                issuer=issuer,
            )
            result["verification"] = verified
        except jwt.ExpiredSignatureError:
            result["verification_error"] = "Token has expired"
            result["verification_error_type"] = "ExpiredSignatureError"
        except jwt.InvalidAudienceError:
            result["verification_error"] = "Invalid audience claim"
            result["verification_error_type"] = "InvalidAudienceError"
        except jwt.InvalidIssuerError:
            result["verification_error"] = "Invalid issuer claim"
            result["verification_error_type"] = "InvalidIssuerError"
        except jwt.InvalidSignatureError:
            result["verification_error"] = "Signature verification failed - token may be tampered"
            result["verification_error_type"] = "InvalidSignatureError"
        except jwt.DecodeError as e:
            result["verification_error"] = f"Token decode error: {e}"
            result["verification_error_type"] = "DecodeError"
        except ValueError as e:
            result["verification_error"] = f"Configuration error: {e}"
            result["verification_error_type"] = "ValueError"
        except jwt.InvalidTokenError as e:
            result["verification_error"] = f"Invalid token: {e}"
            result["verification_error_type"] = "InvalidTokenError"
    else:
        result["verification"] = "Skipped - no secret/key provided. Unverified payload MUST NOT be trusted."

    return result


